// WRONG: authenticated but not authorized
app.get('/invoices/:id', requireAuth, async (req, res) => {
  const invoice = await db.invoices.findById(req.params.id);
  return res.json(invoice); // any logged-in user reads any invoice
});

// RIGHT: scope the query to the principal's tenant
app.get('/invoices/:id', requireAuth, async (req, res) => {
  const invoice = await db.invoices.findOne({
    id: req.params.id,
    tenantId: req.user.tenantId, // AuthZ enforced in the query itself
  });
  if (!invoice) return res.sendStatus(404); // 404, not 403, to avoid leaking existence
  return res.json(invoice);
});

