// Hybrid: RBAC gate + ABAC ownership/amount check
function canApproveExpense(user: User, expense: Expense): boolean {
  if (!user.roles.includes('manager')) return false;            // RBAC
  if (expense.departmentId !== user.departmentId) return false; // ABAC: same dept
  if (expense.amount > user.approvalLimit) return false;        // ABAC: limit
  if (expense.status !== 'pending') return false;               // resource state
  return true;
}

