import { randomBytes, createHash, timingSafeEqual } from 'crypto';

const hashToken = (t: string) => createHash('sha256').update(t).digest('hex');
const newToken = () => randomBytes(32).toString('base64url');
const REFRESH_TTL_MS = 7 * 24 * 60 * 60 * 1000;

interface RefreshRecord {
  tokenHash: string;
  userId: string;
  familyId: string;
  used: boolean;
  expiresAt: number;
}

interface Store {
  findByHash(hash: string): Promise<RefreshRecord | null>;
  markUsed(hash: string): Promise<void>;
  insert(rec: RefreshRecord): Promise<void>;
  revokeFamily(familyId: string): Promise<void>;
  tx<T>(fn: () => Promise<T>): Promise<T>; // serialize the critical section
}

export class ReuseError extends Error {}
export class InvalidTokenError extends Error {}

export async function rotateRefreshToken(
  presented: string,
  store: Store,
  signAccessToken: (userId: string) => string,
): Promise<{ accessToken: string; refreshToken: string }> {
  const presentedHash = hashToken(presented);

  return store.tx(async () => {
    const record = await store.findByHash(presentedHash);

    if (!record || record.expiresAt < Date.now()) {
      throw new InvalidTokenError('unknown or expired refresh token');
    }

    // Reuse detection: an already-rotated token came back => theft.
    if (record.used) {
      await store.revokeFamily(record.familyId);
      throw new ReuseError('refresh token reuse detected; family revoked');
    }

    // Constant-time confirm the hash (defense against partial-match oracles).
    const a = Buffer.from(record.tokenHash);
    const b = Buffer.from(presentedHash);
    if (a.length !== b.length || !timingSafeEqual(a, b)) {
      throw new InvalidTokenError('token mismatch');
    }

    // Rotate: burn the old, mint a new one in the same family.
    await store.markUsed(presentedHash);
    const next = newToken();
    await store.insert({
      tokenHash: hashToken(next),
      userId: record.userId,
      familyId: record.familyId,
      used: false,
      expiresAt: Date.now() + REFRESH_TTL_MS,
    });

    return {
      accessToken: signAccessToken(record.userId),
      refreshToken: next, // caller sets this in an httpOnly Secure cookie
    };
  });
}

import { jwtVerify, createRemoteJWKSet, decodeProtectedHeader, JWTPayload } from 'jose';

const JWKS = createRemoteJWKSet(new URL('https://auth.example.com/.well-known/jwks.json'));
const ISSUER = 'https://auth.example.com';
const AUDIENCE = 'api://invoices';
const ALLOWED_ALGS = ['RS256'];

export class AuthError extends Error {}

interface Claims extends JWTPayload {
  sub: string;
  tokenVersion: number;
}

export async function verifyToken(
  token: string,
  getUserTokenVersion: (userId: string) => Promise<number>,
): Promise<Claims> {
  // Cheap guard: reject 'none' before doing anything else.
  const header = decodeProtectedHeader(token);
  if (!header.alg || !ALLOWED_ALGS.includes(header.alg)) {
    throw new AuthError('unsupported algorithm');
  }

  let payload: JWTPayload;
  try {
    ({ payload } = await jwtVerify(token, JWKS, {
      algorithms: ALLOWED_ALGS, // pin: defeats alg:none and RS/HS confusion
      issuer: ISSUER,
      audience: AUDIENCE,
      clockTolerance: 5,        // seconds of skew; enforces exp/nbf
    }));
  } catch {
    // Uniform error to the caller; log details server-side only.
    throw new AuthError('invalid token');
  }

  const claims = payload as Claims;
  if (typeof claims.sub !== 'string' || typeof claims.tokenVersion !== 'number') {
    throw new AuthError('invalid token');
  }

  // Revocation check: stale-version tokens are rejected even if unexpired.
  const currentVersion = await getUserTokenVersion(claims.sub);
  if (claims.tokenVersion < currentVersion) {
    throw new AuthError('token revoked');
  }

  return claims;
}
